  var arg = arguments[i]
  var type = typeof arg
  if (type === 'object' && arg instanceof Error) {
    err = arg
    status = err.status || err.statusCode || status
  } else if (type === 'number' && i === 0) {
    status = arg
  } else if (type === 'string') {
    msg = arg
